import assert from "node:assert/strict";
import test from "node:test";

import { SERVICE_NAMES } from "./index.js";

test("service contract contains the bootstrap processes", () => {
  assert.deepEqual(SERVICE_NAMES, ["api", "worker"]);
});

export const SERVICE_NAMES = ["api", "worker"] as const;

export type ServiceName = (typeof SERVICE_NAMES)[number];
export type HealthState = "ok" | "degraded" | "error";

export interface HealthResponse {
  service: ServiceName;
  status: HealthState;
  version: string;
  timestamp: string;
  uptimeSeconds: number;
}

export interface ReadinessResponse extends HealthResponse {
  checks: Record<string, "ok" | "error">;
}

export interface SystemInfoResponse {
  name: "docomator";
  version: string;
  architecture: "modular-monolith";
  runtime: {
    node: string;
    platform: NodeJS.Platform;
    arch: string;
  };
  features: {
    offlineFirst: true;
    localLlm: boolean;
    documentFormats: readonly ["docx", "xlsx"];
  };
}

#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";
import process from "node:process";

const roots = ["README.md", "CONTRIBUTING.md", "SECURITY.md", "AGENTS.md", "docs"];
const markdownFiles = [];

function collect(target) {
  if (!fs.existsSync(target)) {
    return;
  }
  const stat = fs.statSync(target);
  if (stat.isFile() && target.endsWith(".md")) {
    markdownFiles.push(target);
    return;
  }
  if (!stat.isDirectory()) {
    return;
  }
  for (const entry of fs.readdirSync(target, { withFileTypes: true })) {
    collect(path.join(target, entry.name));
  }
}

for (const root of roots) {
  collect(root);
}

const failures = [];
const linkPattern = /\[[^\]]*\]\(([^)]+)\)/g;

for (const file of markdownFiles) {
  const content = fs.readFileSync(file, "utf8");
  for (const match of content.matchAll(linkPattern)) {
    let link = match[1]?.trim();
    if (!link || /^(?:https?:|mailto:|#)/.test(link)) {
      continue;
    }
    link = link.split("#", 1)[0];
    if (!link || link.includes("{{")) {
      continue;
    }
    const decoded = decodeURIComponent(link.replace(/^<|>$/g, ""));
    const resolved = path.resolve(path.dirname(file), decoded);
    if (!fs.existsSync(resolved)) {
      failures.push(`${file}: missing ${decoded}`);
    }
  }
}

if (failures.length > 0) {
  process.stderr.write(`${failures.join("\n")}\n`);
  process.exit(1);
}

process.stdout.write(`Checked ${markdownFiles.length} Markdown files.\n`);

#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";

for (const root of ["apps", "packages"]) {
  if (!fs.existsSync(root)) {
    continue;
  }
  for (const entry of fs.readdirSync(root, { withFileTypes: true })) {
    if (!entry.isDirectory()) {
      continue;
    }
    const target = path.join(root, entry.name, "dist");
    fs.rmSync(target, { recursive: true, force: true });
  }
}

#!/usr/bin/env node
const url = process.argv[2] ?? "http://127.0.0.1:8080/readyz";
const timeoutMs = Number.parseInt(process.argv[3] ?? "5000", 10);
const controller = new AbortController();
const timer = setTimeout(() => controller.abort(), timeoutMs);

try {
  const response = await fetch(url, { signal: controller.signal });
  const body = await response.text();
  if (!response.ok) {
    process.stderr.write(`Health check failed: HTTP ${response.status} ${body}\n`);
    process.exit(1);
  }
  process.stdout.write(`${body}\n`);
} catch (error) {
  process.stderr.write(
    `Health check failed: ${error instanceof Error ? error.message : String(error)}\n`
  );
  process.exit(1);
} finally {
  clearTimeout(timer);
}
